import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { RootState } from "@/store";

export type UserRole = "customer" | "admin" | "staff";

export interface AuthUser {
  id: string;
  phone: string;
  name: string;
  role: UserRole;
}

interface AuthState {
  token: string | null;
  user: AuthUser | null;
  isAuthenticated: boolean;
}

const initialState: AuthState = {
  token: null,
  user: null,
  isAuthenticated: false,
};

const authSlice = createSlice({
  name: "auth",
  initialState,
  reducers: {
    setCredentials: (
      state,
      action: PayloadAction<{ token: string; user: AuthUser }>
    ) => {
      state.token = action.payload.token;
      state.user = action.payload.user;
      state.isAuthenticated = true;
    },
    clearCredentials: (state) => {
      state.token = null;
      state.user = null;
      state.isAuthenticated = false;
    },
    updateUserName: (state, action: PayloadAction<string>) => {
      if (state.user) {
        state.user.name = action.payload;
      }
    },
  },
});

export const { setCredentials, clearCredentials, updateUserName } =
  authSlice.actions;

export const selectAuth = (state: RootState) => state.auth;
export const selectCurrentUser = (state: RootState) => state.auth.user;
export const selectIsAuthenticated = (state: RootState) =>
  state.auth.isAuthenticated;

export default authSlice.reducer;

import { createSlice, type PayloadAction } from "@reduxjs/toolkit";
import type { RootState } from "@/store";

export type BookingStep = 1 | 2 | 3 | 4;

interface BookingState {
  currentStep: BookingStep;
  selectedServiceId: string | null;
  serviceCategory: string;
  selectedStaffId: string | null;
  selectedDate: string | null;
  selectedTime: string | null;
  termsAccepted: boolean;
  isSubmitting: boolean;
  bookingComplete: boolean;
  bookingCode: string;
}

const initialState: BookingState = {
  currentStep: 1,
  selectedServiceId: null,
  serviceCategory: "all",
  selectedStaffId: null,
  selectedDate: null,
  selectedTime: null,
  termsAccepted: false,
  isSubmitting: false,
  bookingComplete: false,
  bookingCode: "",
};

const bookingSlice = createSlice({
  name: "booking",
  initialState,
  reducers: {
    setStep: (state, action: PayloadAction<BookingStep>) => {
      state.currentStep = action.payload;
    },
    setSelectedServiceId: (state, action: PayloadAction<string | null>) => {
      state.selectedServiceId = action.payload;
    },
    setServiceCategory: (state, action: PayloadAction<string>) => {
      state.serviceCategory = action.payload;
    },
    setSelectedStaffId: (state, action: PayloadAction<string | null>) => {
      state.selectedStaffId = action.payload;
    },
    setSelectedDate: (state, action: PayloadAction<string | null>) => {
      state.selectedDate = action.payload;
    },
    setSelectedTime: (state, action: PayloadAction<string | null>) => {
      state.selectedTime = action.payload;
    },
    setTermsAccepted: (state, action: PayloadAction<boolean>) => {
      state.termsAccepted = action.payload;
    },
    setIsSubmitting: (state, action: PayloadAction<boolean>) => {
      state.isSubmitting = action.payload;
    },
    setBookingComplete: (
      state,
      action: PayloadAction<{ complete: boolean; code?: string }>
    ) => {
      state.bookingComplete = action.payload.complete;
      if (action.payload.code !== undefined) {
        state.bookingCode = action.payload.code;
      }
    },
    resetBooking: () => initialState,
  },
});

export const {
  setStep,
  setSelectedServiceId,
  setServiceCategory,
  setSelectedStaffId,
  setSelectedDate,
  setSelectedTime,
  setTermsAccepted,
  setIsSubmitting,
  setBookingComplete,
  resetBooking,
} = bookingSlice.actions;

export const selectBookingStep = (state: RootState) =>
  state.booking.currentStep;
export const selectBookingState = (state: RootState) => state.booking;

export default bookingSlice.reducer;

import { configureStore } from "@reduxjs/toolkit";
import authReducer from "@/store/slices/authSlice";
import bookingReducer from "@/store/slices/bookingSlice";

export const makeStore = () =>
  configureStore({
    reducer: {
      auth: authReducer,
      booking: bookingReducer,
    },
    devTools: process.env.NODE_ENV !== "production",
  });

export type AppStore = ReturnType<typeof makeStore>;
export type RootState = ReturnType<AppStore["getState"]>;
export type AppDispatch = AppStore["dispatch"];

import { useDispatch, useSelector, useStore } from "react-redux";
import type { AppDispatch, AppStore, RootState } from "@/store";

export const useAppDispatch = useDispatch.withTypes<AppDispatch>();
export const useAppSelector = useSelector.withTypes<RootState>();
export const useAppStore = useStore.withTypes<AppStore>();

"use client";

import { useRef, type ReactNode } from "react";
import { Provider } from "react-redux";
import { makeStore, type AppStore } from "@/store";

interface StoreProviderProps {
  children: ReactNode;
}

export function StoreProvider({ children }: StoreProviderProps) {
  const storeRef = useRef<AppStore | null>(null);

  if (!storeRef.current) {
    storeRef.current = makeStore();
  }

  return <Provider store={storeRef.current}>{children}</Provider>;
}

